use crate::helpers::spawn_app;

/// Helper: creates a reqwest client with cookie store, registers a user,
/// and logs in, returning the authenticated client.
async fn authenticated_client(address: &str) -> reqwest::Client {
    let client = reqwest::Client::builder()
        .cookie_store(true)
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    // Register
    let resp = client
        .post(format!("{address}/register"))
        .form(&[
            ("email", "todo-user@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to register");
    assert_eq!(resp.status().as_u16(), 303, "Registration should succeed");

    // Login
    let resp = client
        .post(format!("{address}/login"))
        .form(&[
            ("email", "todo-user@example.com"),
            ("password", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to login");
    assert_eq!(resp.status().as_u16(), 303, "Login should succeed");

    client
}

#[tokio::test]
async fn get_todos_redirects_to_login_when_not_authenticated() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Expected redirect for unauthenticated user"
    );

    let location = response
        .headers()
        .get("location")
        .expect("Missing Location header")
        .to_str()
        .unwrap();
    assert_eq!(
        location, "/login",
        "Should redirect to /login when not authenticated"
    );
}

#[tokio::test]
async fn get_todos_returns_200_with_empty_state_for_authenticated_user() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(response.status().as_u16(), 200);

    let body = response.text().await.unwrap();

    // Page structure
    assert!(body.contains("My Todos"), "Missing page heading");
    assert!(
        body.contains("My Todos -- Todo List"),
        "Missing descriptive page title"
    );

    // Empty state message
    assert!(
        body.contains("No todos yet."),
        "Should show empty state message"
    );

    // Add todo form
    assert!(
        body.contains("<label for=\"title\">New todo</label>"),
        "Missing label for add todo input"
    );
    assert!(
        body.contains("name=\"title\""),
        "Missing title input field"
    );
    assert!(
        body.contains(">Add todo</button>"),
        "Missing add todo button"
    );

    // Sign out button in nav
    assert!(
        body.contains(">Sign out</button>"),
        "Missing sign out button"
    );

    // No todo list when empty
    assert!(
        !body.contains("todo-list"),
        "Should not render todo list when empty"
    );
}

#[tokio::test]
async fn post_todo_adds_item_and_redirects() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    let response = client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "Buy groceries")])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Expected redirect after adding todo"
    );

    let location = response
        .headers()
        .get("location")
        .expect("Missing Location header")
        .to_str()
        .unwrap();
    assert_eq!(
        location, "/todos",
        "Should redirect back to /todos after adding"
    );
}

#[tokio::test]
async fn post_todo_persists_and_displays_item() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    // Add a todo
    client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "Buy groceries")])
        .send()
        .await
        .expect("Failed to add todo");

    // Fetch the list (follow the redirect manually)
    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to fetch todos");

    assert_eq!(response.status().as_u16(), 200);

    let body = response.text().await.unwrap();

    assert!(
        body.contains("Buy groceries"),
        "Todo item should appear in the list"
    );
    assert!(
        !body.contains("No todos yet."),
        "Empty state should not show when items exist"
    );
    assert!(
        body.contains("todo-list"),
        "Todo list container should be present"
    );
}

#[tokio::test]
async fn post_todo_with_empty_title_silently_redirects() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    let response = client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "")])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Empty title should silently redirect"
    );

    // Verify no todo was added
    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to fetch todos");

    let body = response.text().await.unwrap();
    assert!(
        body.contains("No todos yet."),
        "No todo should have been added for empty title"
    );
}

#[tokio::test]
async fn post_todo_with_whitespace_only_title_silently_redirects() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    let response = client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "   ")])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Whitespace-only title should silently redirect"
    );
}

#[tokio::test]
async fn post_todo_with_title_too_long_returns_422() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    let long_title = "a".repeat(301);

    let response = client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", long_title.as_str())])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        422,
        "Title exceeding max length should return 422"
    );

    let body = response.text().await.unwrap();
    assert!(
        body.contains("too long"),
        "Should show title length error"
    );
}

#[tokio::test]
async fn post_todo_redirects_to_login_when_not_authenticated() {
    let app = spawn_app().await;

    let client = reqwest::Client::builder()
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    let response = client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "Buy groceries")])
        .send()
        .await
        .expect("Failed to execute request");

    assert_eq!(
        response.status().as_u16(),
        303,
        "Expected redirect for unauthenticated POST"
    );

    let location = response
        .headers()
        .get("location")
        .expect("Missing Location header")
        .to_str()
        .unwrap();
    assert_eq!(
        location, "/login",
        "Should redirect to /login when not authenticated"
    );
}

#[tokio::test]
async fn multiple_todos_are_displayed_in_order() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    // Add multiple todos
    for title in &["First task", "Second task", "Third task"] {
        client
            .post(format!("{}/todos", &app.address))
            .form(&[("title", *title)])
            .send()
            .await
            .expect("Failed to add todo");
    }

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to fetch todos");

    let body = response.text().await.unwrap();

    assert!(body.contains("First task"), "Missing first todo");
    assert!(body.contains("Second task"), "Missing second todo");
    assert!(body.contains("Third task"), "Missing third todo");

    // Verify order: First should appear before Second, Second before Third
    let first_pos = body.find("First task").unwrap();
    let second_pos = body.find("Second task").unwrap();
    let third_pos = body.find("Third task").unwrap();
    assert!(
        first_pos < second_pos && second_pos < third_pos,
        "Todos should be in creation order"
    );
}

#[tokio::test]
async fn users_only_see_their_own_todos() {
    let app = spawn_app().await;

    // User A registers, logs in, adds a todo
    let client_a = reqwest::Client::builder()
        .cookie_store(true)
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    client_a
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "user-a@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to register user A");

    client_a
        .post(format!("{}/login", &app.address))
        .form(&[
            ("email", "user-a@example.com"),
            ("password", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to login user A");

    client_a
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "User A secret todo")])
        .send()
        .await
        .expect("Failed to add todo for user A");

    // User B registers, logs in, adds a different todo
    let client_b = reqwest::Client::builder()
        .cookie_store(true)
        .redirect(reqwest::redirect::Policy::none())
        .build()
        .unwrap();

    client_b
        .post(format!("{}/register", &app.address))
        .form(&[
            ("email", "user-b@example.com"),
            ("password", "securepassword123"),
            ("password_confirmation", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to register user B");

    client_b
        .post(format!("{}/login", &app.address))
        .form(&[
            ("email", "user-b@example.com"),
            ("password", "securepassword123"),
        ])
        .send()
        .await
        .expect("Failed to login user B");

    client_b
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "User B public todo")])
        .send()
        .await
        .expect("Failed to add todo for user B");

    // User B should NOT see User A's todos
    let response = client_b
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to fetch todos for user B");

    let body = response.text().await.unwrap();
    assert!(
        body.contains("User B public todo"),
        "User B should see their own todo"
    );
    assert!(
        !body.contains("User A secret todo"),
        "User B should NOT see User A's todo"
    );
}

#[tokio::test]
async fn todo_with_special_characters_is_escaped_in_html() {
    let app = spawn_app().await;
    let client = authenticated_client(&app.address).await;

    client
        .post(format!("{}/todos", &app.address))
        .form(&[("title", "Buy <script>alert('xss')</script> items")])
        .send()
        .await
        .expect("Failed to add todo");

    let response = client
        .get(format!("{}/todos", &app.address))
        .send()
        .await
        .expect("Failed to fetch todos");

    let body = response.text().await.unwrap();

    // The title should be HTML-escaped, not rendered as a script tag
    assert!(
        !body.contains("<script>"),
        "Script tags should be escaped in todo titles"
    );
    assert!(
        body.contains("&lt;script&gt;") || body.contains("&#x3c;script"),
        "Special characters should be HTML-escaped"
    );
}

